14	const willBeAlive = (isAlive: boolean, neighborCount: number): boolean =>
15	  isAlive ? neighborCount === 2 || neighborCount === 3 : neighborCount === 3;
16	
17	export function nextGeneration(grid: boolean[][]): boolean[][] {
18	  if (grid.length === 1 && grid[0].length === 1) return [[]];
19	  return grid.map((row, rowIndex) =>
20	    row.map((cell, colIndex) =>
21	      willBeAlive(cell, countNeighbors(grid, rowIndex, colIndex))
22	    )
23	  );
24	}
